import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.reportei.com/";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Reportei API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:reportei",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const reporteiFirewall = {",
    '  name: "reportei",',
    '  description: "Reportei API",',
    "  placeholders: {",
    `    REPORTEI_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://app.reportei.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.REPORTEI_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Reportei firewall config...");
  const ts = generateTypeScript();
  writeOutput("reportei", ts, import.meta.dirname);
}
